export function module2FrameNeedsExplicitReview(frameStatus = '', frameConfirmation = '') {
  if (['confirmed', 'revised'].includes(frameConfirmation)) return false;
  return ['drift', 'thin', 'unresolved'].includes(frameStatus);
}

export function module2SetNeedsExplicitReview(coverageStatus = '', setConfirmation = '') {
  return coverageStatus !== 'covered';
}

export function module2LockTransitionJudgments({
  frameStatus = '',
  frameConfirmation = '',
  coverageStatus = '',
  setConfirmation = '',
  selectedBetId = '',
} = {}) {
  const judgments = { selectedBetId };
  if (!module2FrameNeedsExplicitReview(frameStatus, frameConfirmation)
      && !['confirmed', 'revised'].includes(frameConfirmation)) {
    judgments.frameConfirmation = 'confirmed';
  }
  if (!module2SetNeedsExplicitReview(coverageStatus, setConfirmation)
      && !['confirmed', 'confirmed_after_review'].includes(setConfirmation)) {
    judgments.setCompletenessConfirmation = 'confirmed';
  }
  return judgments;
}

export function renderModule2Page() {
  return `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
  <meta name="robots" content="noindex,nofollow">
  <title>Bet Selection - Decision Manifold Studio</title>
  <style>
    :root{--bg:#f7f8f5;--paper:#fff;--ink:#121715;--muted:#59615d;--line:#d9ded9;--soft:#eef2ee;--blue:#183e5a;--green:#2f6f52;--gold:#8a641e;--red:#8a3030;--sans:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;--serif:"Times New Roman",Times,Georgia,serif;--mono:"SFMono-Regular",ui-monospace,Menlo,monospace}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--ink);font:15px/1.48 var(--sans)}button,input,textarea,select{font:inherit}button{min-height:38px;border:1px solid var(--blue);border-radius:4px;background:var(--blue);color:#fff;padding:8px 13px;cursor:pointer}button.secondary{background:#fff;color:var(--ink);border-color:#aeb7b1}button.quiet{background:transparent;color:var(--blue);border-color:transparent;padding-left:2px;padding-right:2px}button.danger{background:#fff;color:var(--red);border-color:#caa}button:disabled{opacity:.45;cursor:not-allowed}a{color:inherit}input,textarea,select{width:100%;border:1px solid #b8c0ba;border-radius:3px;background:#fff;color:var(--ink);padding:9px 10px}textarea{min-height:112px;resize:vertical}label{display:block;margin:0 0 5px;color:var(--muted);font-size:12px;font-weight:650;text-transform:uppercase;letter-spacing:.05em}.shell{max-width:1320px;margin:auto;padding:18px}.topbar{display:flex;align-items:center;justify-content:space-between;gap:18px;padding-bottom:14px;border-bottom:1px solid var(--line)}.brand b{display:block;font:500 24px/1.05 var(--serif)}.brand span,.meta{color:var(--muted);font-size:12.5px}.top-actions,.actions,.segmented,.module-tabs{display:flex;align-items:center;gap:8px;flex-wrap:wrap}.module-tabs{border:1px solid var(--line);border-radius:4px;background:#fff;padding:3px}.module-tabs a{padding:6px 10px;border-radius:2px;text-decoration:none;font-size:13px}.module-tabs a.active{background:var(--ink);color:#fff}.usage{min-width:145px}.usage-line{display:flex;justify-content:space-between;font:11px var(--mono);color:var(--muted);margin-bottom:4px}.usage progress{width:100%;height:7px;display:block;accent-color:var(--green)}.layout{display:grid;grid-template-columns:220px minmax(0,1fr);gap:18px;margin-top:18px;align-items:start}.sidebar{position:sticky;top:14px;background:#fff;border:1px solid var(--line)}.step{display:flex;width:100%;justify-content:space-between;align-items:center;border:0;border-bottom:1px solid var(--line);border-radius:0;background:#fff;color:var(--ink);text-align:left;padding:13px}.step.active{background:var(--blue);color:#fff}.step:last-child{border-bottom:0}.step small{font:11px var(--mono);opacity:.7}.panel{background:#fff;border:1px solid var(--line)}.panel-head{display:flex;justify-content:space-between;gap:18px;padding:18px;border-bottom:1px solid var(--line)}.panel-head h1{font:500 34px/1.08 var(--serif);margin:0}.panel-head p{max-width:720px;margin:7px 0 0;color:#343a37}.panel-body{padding:18px}.section{margin-bottom:22px}.section h2{font-size:16px;margin:0 0 10px}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}.grid-3{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px}.field{margin-bottom:14px}.inheritance{padding:14px;background:var(--soft);border-left:4px solid var(--blue);margin-bottom:18px}.inheritance strong{font-family:var(--serif);font-size:18px}.frame{margin:8px 0 0;font-family:var(--serif);font-size:17px}.bet-list{display:grid;gap:10px}.bet-edit,.bet-card,.ground-row,.lock-block,.hard-stop{border:1px solid var(--line);border-radius:4px;background:#fff;padding:14px}.bet-edit .grid{grid-template-columns:minmax(0,.55fr) minmax(0,1fr)}.grounding{border:1px solid var(--line);margin-bottom:18px}.grounding summary{cursor:pointer;padding:13px 15px;font-weight:700;background:var(--soft)}.grounding-body{padding:0 15px}.ground-row{border-width:0 0 1px;border-radius:0;padding:14px 0}.ground-row:last-child{border-bottom:0}.row-head{display:flex;justify-content:space-between;gap:12px;align-items:start}.tag{display:inline-block;border:1px solid #aeb7b1;border-radius:3px;padding:2px 6px;font:11px var(--mono);color:var(--muted);white-space:nowrap}.tag.good{color:var(--green);border-color:#8ab09a}.tag.warn{color:var(--gold);border-color:#c9ad74}.tag.bad{color:var(--red);border-color:#c98e8e}.hard-stop{border-color:#c98989;background:#fff8f8;margin:12px 0}.hard-stop strong{color:var(--red)}.rank-list{display:grid;gap:12px}.bet-card{display:grid;grid-template-columns:54px minmax(0,1fr);gap:12px}.rank{font:500 25px var(--serif);color:var(--blue)}.bet-card h3{font-size:18px;margin:0 0 5px}.bet-card p{margin:5px 0}.evidence{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:10px}.evidence div{background:var(--soft);padding:9px;font-size:13px}.comparison{color:var(--blue);font-weight:650}.weight-row{display:grid;grid-template-columns:minmax(130px,1fr) minmax(180px,2fr) 58px;gap:10px;align-items:center;padding:9px 0;border-bottom:1px solid var(--line)}.weight-row:last-child{border-bottom:0}.weight-row input[type=range]{padding:0;border:0}.radio-card{display:flex;align-items:center;gap:8px;border:1px solid var(--line);border-radius:4px;padding:10px;background:#fff;color:var(--ink);text-transform:none;letter-spacing:0;font-size:14px;margin:0}.radio-card input{width:auto}.roster{display:flex;gap:7px;flex-wrap:wrap;margin:8px 0}.roster button{min-height:32px}.held-row{display:grid;grid-template-columns:minmax(0,1fr) 40px;gap:8px;margin-bottom:8px}.sticky-action{position:sticky;bottom:0;background:rgba(255,255,255,.97);border-top:1px solid var(--line);padding:12px 0 2px;margin-top:18px}.status{min-height:20px;color:var(--muted);font-size:13px}.empty{border:1px dashed #aeb7b1;padding:18px;color:var(--muted)}.auth{max-width:760px;margin:50px auto;background:#fff;border:1px solid var(--line);padding:22px}.auth h1{font:500 34px var(--serif);margin:0 0 8px}.auth h2{font-size:17px}.auth .grid{grid-template-columns:repeat(2,minmax(0,1fr))}.hidden{display:none!important}details>summary{user-select:none}.soft-copy{color:var(--muted);font-size:13px}.selected-bet{border-left:4px solid var(--green)}.pdf-preview{width:100%;height:720px;border:1px solid var(--line);background:var(--soft)}.version-list{display:grid;gap:7px}.version-row{display:flex;align-items:center;justify-content:space-between;gap:12px;border:1px solid var(--line);padding:9px 11px}.version-row a{color:var(--blue);font-weight:650}
    button.assist{background:var(--green);border-color:var(--green)}
    @media(max-width:860px){.shell{padding:12px}.topbar,.panel-head{align-items:stretch;flex-direction:column}.layout{grid-template-columns:1fr}.sidebar{position:static;display:grid;grid-template-columns:repeat(3,1fr)}.step{border-bottom:0;border-right:1px solid var(--line);padding:10px;font-size:13px}.step:last-child{border-right:0}.grid,.grid-3,.bet-edit .grid,.evidence,.auth .grid{grid-template-columns:1fr}.panel-body{padding:14px}.panel-head h1{font-size:29px}.bet-card{grid-template-columns:40px minmax(0,1fr)}.grounding:not([open]) .grounding-body{display:none}.weight-row{grid-template-columns:minmax(0,1fr) 44px;gap:6px}.weight-row input{grid-column:1/-1}.sticky-action{margin-left:-14px;margin-right:-14px;padding:10px 14px}.module-tabs{order:3;width:100%}.module-tabs a{flex:1;text-align:center}.pdf-preview{height:520px}.version-row{align-items:flex-start;flex-direction:column}}
  </style>
</head>
<body><div id="app" class="shell"><div class="auth"><h1>Bet Selection</h1><p class="meta">Loading workspace.</p></div></div>
<script>
  const app=document.getElementById('app');
  const module2FrameNeedsExplicitReview=${module2FrameNeedsExplicitReview.toString()};
  const module2SetNeedsExplicitReview=${module2SetNeedsExplicitReview.toString()};
  const module2LockTransitionJudgments=${module2LockTransitionJudgments.toString()};
  const STEPS=[['ground','Ground'],['board','Board'],['lock','Lock']];
  const HELP={ground:"Bring Bethany House's reply and the current options into one grounded field.",board:'Check what was understood, compare every live bet, and choose what to carry.',lock:'Name who carries the loss, where accountability sits, and how reversible the bet is.'};
  const ROSTER=['Executive Director','Board','Program staff','Community partner','Clients and residents'];
  let me=null,bundle=null,state=null,currentStep='ground',busy=false,statusText='',frameEditing=false,replyEditing=false,replyCorrectionText='',boardAddingBetId='',pdfPreviewUrl='',pdfPreviewBlob=null,pdfPreviewFilename='';
  init();

  async function init(){
    try{
      const session=await api('/api/studio/me');
      if(!session.registered){renderAuth();return}
      me=session;
      await loadWorkspace();
    }catch(error){if(error.status===401)renderAuth(error);else renderFatal(error)}
  }

  async function loadWorkspace(){
    bundle=await api('/api/studio/modules/module-2/workspace');
    state=bundle.state;
    initializeGroundSelection();
    currentStep=['ground','board','lock'].includes(bundle.workspace?.current_step)?bundle.workspace.current_step:'ground';
    ensureWeights();
    render();
  }

  async function api(path,options={}){
    const headers=new Headers(options.headers||{});headers.set('Content-Type','application/json');
    const response=await fetch(path,{...options,headers});
    const data=await response.json().catch(()=>({}));
    if(!response.ok){const error=new Error(data.error||'Request failed');error.status=response.status;throw error}
    return data;
  }

  function renderAuth(error){
    app.innerHTML=\`<div class="auth"><h1>Decision Manifold Studio</h1><p class="meta">\${escapeHtml(error?.message||'Log in or create an account with the class code.')}</p><div class="grid"><section><h2>Log in</h2>\${field('Email','loginEmail','email','maya@example.com')}\${field('Password','loginPassword','password','Your password')}<button data-action="login">Log in</button></section><section><h2>Register</h2>\${field('Name','regName','text','Maya Shah')}\${field('Email','regEmail','email','maya@example.com')}\${field('Password','regPassword','password','At least 8 characters')}\${field('Class code','regClassCode','text','Shared in class')}<button data-action="register">Create account</button></section></div><p class="status">\${escapeHtml(statusText)}</p></div>\`;
  }

  function field(label,id,type,placeholder){return \`<div class="field"><label for="\${id}">\${label}</label><input id="\${id}" type="\${type}" placeholder="\${placeholder}"></div>\`}
  function renderFatal(error){app.innerHTML=\`<div class="auth"><h1>Bet Selection</h1><p>\${escapeHtml(error.message)}</p><button onclick="location.reload()">Try again</button></div>\`}

  function render(){
    const usage=bundle?.usage||me?.usage||{};
    app.innerHTML=\`<header class="topbar"><div class="brand"><b>Decision Manifold Studio</b><span>Bethany House engagement</span></div><nav class="module-tabs" aria-label="Assignment modules"><a href="/decision-engineering">Inquiry</a><a class="active" href="/decision-engineering/module-2">Bet Selection</a></nav><div class="top-actions"><div class="usage"><div class="usage-line"><span>MODEL USE</span><span>\${money(usage.used_micros)} / \${money(usage.limit_micros||10000000)}</span></div><progress max="\${Number(usage.limit_micros||10000000)}" value="\${Number(usage.used_micros||0)}"></progress></div><button class="secondary" data-action="save">Save</button><button class="secondary" data-action="logout">Log out</button></div></header><div class="layout"><aside class="sidebar">\${STEPS.map(([id,label],index)=>\`<button class="step \${currentStep===id?'active':''}" data-step="\${id}"><span>\${label}</span><small>0\${index+1}</small></button>\`).join('')}</aside><main class="panel"><div class="panel-head"><div><h1>\${stepLabel()}</h1><p>\${HELP[currentStep]}</p></div><div class="meta">\${summary()}</div></div><div class="panel-body">\${renderStep()}<p class="status">\${escapeHtml(statusText)}</p></div></main></div>\`;
  }

  function stepLabel(){return STEPS.find(([id])=>id===currentStep)?.[1]||''}
  function summary(){const live=admittedBets().length;return \`\${live} live bet\${live===1?'':'s'} · \${state.inheritance.entryState} inheritance\`}
  function renderStep(){setTimeout(decorateAdaptiveInputs,0);return currentStep==='ground'?renderGround():currentStep==='board'?renderBoard():renderLock()}

  function decorateAdaptiveInputs(){
    document.querySelectorAll('button[data-action="suggest"]').forEach(button=>{button.classList.remove('secondary');button.classList.add('assist')});
    if(currentStep==='board'){const grounding=document.querySelector('details.grounding');if(grounding){grounding.open=true;const summary=grounding.querySelector('summary');if(summary&&summary.textContent.endsWith('· ready'))summary.textContent=summary.textContent.replace('· ready','· check before deciding');const body=grounding.querySelector('.grounding-body');if(body)body.insertAdjacentHTML('beforeend',renderFogProbe())}}
    if(currentStep==='lock'&&!lockReady()){const note=document.querySelector('.sticky-action .soft-copy');if(note)note.textContent='Name the loss bearer and accountability, then explain the reversibility judgment before packaging.'}
    if(replyEditing&&currentStep==='board'){const box=document.querySelector('textarea[data-path="ground.rawReply"]');if(box){box.removeAttribute('data-path');box.id='replyCorrection';box.value=replyCorrectionText;box.placeholder='Paste only the Bethany House lines that should govern the comparison.';const label=box.closest('.field')?.querySelector('label');if(label)label.textContent='Paste only the relevant lines'}}
    if(currentStep==='board'){document.querySelectorAll('button[data-action="select-bet"]').forEach((button,index)=>{if(index===0||(state.ranking.nearTie&&index===1))return;const field=document.createElement('div');field.className='field';field.innerHTML='<label>Why carry this instead of the current leader?</label><textarea data-path="locks.convictionNote" placeholder="Name the evidence or consequence that outweighs the current comparison.">'+escapeHtml(state.locks.convictionNote||'')+'</textarea>';button.parentElement.insertBefore(field,button)})}
  }

  function renderGround(){
    const inherited=state.inheritance;
    const frame=inherited.frame||state.ground.problemSeed;
    const options=availableGroundOptions();
    return \`<section class="inheritance"><strong>\${entryTitle(inherited.entryState)}</strong><div class="soft-copy">\${inherited.highValueTraces.length} high-value traces and \${inherited.inheritedSolutions.length} inherited options</div>\${frame?\`<p class="frame">“\${escapeHtml(frame)}”</p><div class="soft-copy">This frame will be checked against the reply on the Board.</div>\`:''}</section>\${inherited.entryState==='fresh'?\`<div class="field"><label>What is the decision Bethany House faces?</label><textarea data-path="ground.problemSeed" placeholder="Example: Bethany House needs to add operating capacity without losing relationship continuity.">\${escapeHtml(state.ground.problemSeed)}</textarea></div>\`:''}<div class="field"><label>Bethany House reply</label><textarea data-path="ground.rawReply" placeholder="Paste the consolidated reply, including quoted context if useful.">\${escapeHtml(state.ground.rawReply)}</textarea></div><section class="section"><h2>Bulk input</h2><div class="field"><label>One option per line</label><textarea data-path="ground.solutionPaste" placeholder="Select ambassador - screen and verify&#10;Hire directly - add capacity under one accountable role">\${escapeHtml(state.ground.solutionPaste)}</textarea><div class="actions" style="margin-top:8px"><button class="secondary" data-action="update-ground-options" \${busy?'disabled':''}>Update options</button><span class="soft-copy">An inline dash separates an option name from its description.</span></div></div></section><section class="section"><div class="row-head"><div><h2>Options to carry forward</h2><p class="soft-copy">\${state.ground.pickedIds.length} of \${options.length} selected</p></div><button class="secondary" data-action="add-bet">Add option</button></div><div class="bet-list">\${options.length?options.map(renderGroundOption).join(''):'<div class="empty">Paste options above, add one manually, or ask the assistant for suggestions.</div>'}</div></section><div class="sticky-action"><div class="actions"><button data-action="ground-go" \${busy?'disabled':''}>Reconcile and continue</button><button class="secondary" data-action="suggest" \${busy?'disabled':''}>Suggest options</button></div></div>\`;
  }

  function renderGroundOption(bet){const checked=state.ground.pickedIds.includes(bet.id);return \`<article class="bet-edit"><div class="row-head"><label class="radio-card"><input type="checkbox" data-pick="\${escapeAttr(bet.id)}" \${checked?'checked':''}> Carry forward</label><div class="actions"><span class="tag \${bet.provisional?'warn':'good'}">\${bet.provisional?'PROVISIONAL':bet.origin.toUpperCase()}</span><button class="quiet" data-action="remove-pick-option" data-id="\${escapeAttr(bet.id)}">Remove</button></div></div><div class="grid" style="margin-top:10px"><div class="field"><label>Name</label><input data-bet="\${escapeAttr(bet.id)}" data-field="name" value="\${escapeAttr(bet.name)}" placeholder="Example: Phased relationship handoff"></div><div class="field"><label>What this option changes</label><textarea data-bet="\${escapeAttr(bet.id)}" data-field="description" placeholder="Describe the option in concrete terms.">\${escapeHtml(bet.description)}</textarea></div></div></article>\`}
  function availableGroundOptions(){const excluded=new Set(state.ground.excludedOptionIds||[]);const byId=new Map();[...(state.inheritance.inheritedSolutions||[]),...(state.ground.pickOptions||[]),...(state.bets||[])].forEach(option=>{if(option?.id&&!excluded.has(option.id))byId.set(option.id,option)});return [...byId.values()]}
  function initializeGroundSelection(){const hadPrepared=Boolean(state.ground.pickOptions?.length);state.ground.pickOptions=availableGroundOptions();if(!hadPrepared)state.ground.pickedIds=state.ground.pickOptions.map(option=>option.id);syncSelectedGroundBets()}
  function syncSelectedGroundBets(){const selected=new Set(state.ground.pickedIds||[]);state.bets=availableGroundOptions().filter(option=>selected.has(option.id))}
  function includeNewGroundBets(){const known=new Set((state.ground.pickOptions||[]).map(option=>option.id));const additions=(state.bets||[]).filter(option=>!known.has(option.id));if(!additions.length)return;state.ground.pickOptions=[...(state.ground.pickOptions||[]),...additions];state.ground.pickedIds=[...new Set([...(state.ground.pickedIds||[]),...additions.map(option=>option.id)])]}

  function renderBetEdit(bet){return \`<article class="bet-edit"><div class="row-head"><span class="tag \${bet.provisional?'warn':'good'}">\${bet.provisional?'PROVISIONAL':bet.origin.toUpperCase()}</span><button class="quiet" data-action="remove-bet" data-id="\${escapeAttr(bet.id)}">Remove</button></div><div class="grid"><div class="field"><label>Name</label><input data-bet="\${escapeAttr(bet.id)}" data-field="name" value="\${escapeAttr(bet.name)}" placeholder="Example: Phased relationship handoff"></div><div class="field"><label>What this bet changes</label><textarea data-bet="\${escapeAttr(bet.id)}" data-field="description" placeholder="Describe the option in concrete terms.">\${escapeHtml(bet.description)}</textarea></div></div>\${bet.provisional?\`<button class="secondary" data-action="admit-bet" data-id="\${escapeAttr(bet.id)}">Add to live comparison</button>\`:''}</article>\`}

  function renderBoard(){
    const hard=boardBlockers();
    const ordered=orderedBets();
    const groundOpen=hard.length||state.ground.voiceDisagreement.status==='possible';
    return \`<details class="grounding" \${groundOpen?'open':''}><summary>What I understood \${hard.length?\`· \${hard.length} item\${hard.length===1?'':'s'} to resolve\`:'· ready'}</summary><div class="grounding-body">\${renderFrameRow()}\${renderReplyRow()}\${renderVoiceRow()}\${renderDuplicateReview()}</div></details>\${hard.map(item=>\`<div class="hard-stop"><strong>Resolve before locking</strong><p>\${escapeHtml(item.message)}</p>\${item.action==='ground'?'<button class="secondary" data-step="ground">Return to Ground</button>':''}\${item.action==='evaluate'?'<button data-action="evaluate">Evaluate live bets</button>':''}\${item.action==='options'?'<div class="actions"><button data-action="show-provisional">Review suggested options</button><button class="secondary" data-action="suggest">Suggest another option</button></div>':''}\${item.action==='set'?'<button class="secondary" data-action="confirm-set">I reviewed the gap; carry this set</button>':''}</div>\`).join('')}<section class="section"><div class="row-head"><div><h2>Ranked bets</h2><div class="soft-copy">Least evidence against across the live comparison field</div></div><div class="actions"><button class="secondary" data-action="add-bet-board">Add option</button><button class="secondary" data-action="suggest">Suggest options</button></div></div>\${renderBoardBetEditor()}\${renderProvisionalBets()}<div class="rank-list">\${ordered.length?ordered.map((bet,index)=>renderBetCard(bet,index)).join(''):'<div class="empty">Reconcile and evaluate at least two live options to build the Board.</div>'}</div></section>\${renderSetLine()}\${renderWeights()}<div class="sticky-action">\${renderBoardAction()}</div>\`;
  }

  function renderFrameRow(){const frame=state.ground.frameComparison||{};const confirmed=['confirmed','revised'].includes(state.locks.frameConfirmation);const hard=module2FrameNeedsExplicitReview(frame.status,state.locks.frameConfirmation);const current=frame.groundedFrame||state.inheritance.frame||state.ground.problemSeed||'';const tag=confirmed?'CONFIRMED':hard?escapeHtml(frame.status||'unresolved'):'CONSISTENT';return \`<div class="ground-row"><div class="row-head"><strong>Frame</strong><span class="tag \${hard?'bad':'good'}">\${tag}</span></div>\${frameEditing?\`<div class="field"><label>Revised decision frame</label><textarea data-path="ground.frameComparison.groundedFrame" placeholder="State the decision Bethany House is actually making.">\${escapeHtml(current)}</textarea></div><div class="actions"><button data-action="save-frame-revision">Use revised frame</button><button class="secondary" data-action="cancel-frame-revision">Cancel</button></div>\`:\`<p class="frame">“\${escapeHtml(current||'No frame yet')}”</p><p class="soft-copy">\${escapeHtml(frame.reason||'')}</p>\${hard?\`<div class="actions"><button class="secondary" data-action="confirm-frame">Keep this frame</button><button class="secondary" data-action="revise-frame">Revise it</button></div>\`:!confirmed?'<p class="soft-copy">This consistent frame will be accepted when you take a bet to Lock.</p><button class="quiet" data-action="revise-frame">Revise it</button>':''}\`}</div>\`}
  function renderReplyRow(){const lines=state.ground.substantiveLines||[];return \`<div class="ground-row"><div class="row-head"><strong>Reply extraction</strong><span class="tag \${lines.length?'good':'warn'}">\${lines.length} lines</span></div>\${replyEditing?\`<div class="field"><label>Correct Bethany House reply</label><textarea data-path="ground.rawReply" placeholder="Keep only the relevant reply and quoted context.">\${escapeHtml(state.ground.rawReply)}</textarea></div><div class="actions"><button data-action="reconcile-reply">Use corrected reply</button><button class="secondary" data-action="cancel-reply-edit">Cancel</button></div>\`:\`\${lines.length?\`<ul>\${lines.map(line=>\`<li>\${escapeHtml(line)}</li>\`).join('')}</ul>\`:'<p class="soft-copy">No substantive lines could be verified.</p>'}<button class="quiet" data-action="edit-reply">Correct the extracted reply</button>\`}</div>\`}
  function renderFogProbe(){const fog=(state.ground.fogMap||[]).filter(item=>['partial','dodged','unaddressed'].includes(item.status)).sort((a,b)=>Number(b.influence||0)-Number(a.influence||0));const probe=fog[0];if(!probe)return '<div class="ground-row"><div class="row-head"><strong>Open dependencies</strong><span class="tag good">NONE CRITICAL</span></div><p class="soft-copy">The supplied reply does not leave an inherited high-value trace visibly open.</p></div>';return \`<div class="ground-row"><div class="row-head"><strong>Question that could change the comparison</strong><span class="tag warn">\${escapeHtml(String(probe.status||'open').toUpperCase())}</span></div><p>\${escapeHtml(probe.question||'Which unresolved dependency would most change the ranking?')}</p><p class="soft-copy">This is the highest-influence open dependency in the current reply. Resolve it with Bethany House or carry it explicitly as a tripwire.</p></div>\`}
  function renderVoiceRow(){const voice=state.ground.voiceDisagreement||{};if(voice.status==='confirmed')return \`<div class="ground-row"><div class="row-head"><strong>Disagreement between voices</strong><span class="tag good">CONFIRMED</span></div><p>\${escapeHtml(voice.summary||'The attributed voices express different positions.')}</p><div class="soft-copy">Carried forward as an open dependency in this comparison.</div></div>\`;if(voice.status!=='possible')return '';return \`<div class="ground-row"><div class="row-head"><strong>Possible disagreement between voices</strong><span class="tag warn">HEURISTIC</span></div><p>\${escapeHtml(voice.summary||'The reply may contain more than one position.')}</p><div class="soft-copy">\${(voice.evidenceLines||[]).map(escapeHtml).join(' · ')}</div><div class="actions"><button class="secondary" data-action="voice-yes">Yes, keep this unresolved</button><button class="secondary" data-action="voice-no">Same position</button></div></div>\`}
  function renderDuplicateReview(){const byId=new Map(state.bets.map(bet=>[bet.id,bet]));const pairs=(state.ground.possibleDuplicates||[]).filter(pair=>pair.status!=='dismissed'&&byId.has(pair.leftId)&&byId.has(pair.rightId));if(!pairs.length)return '';return pairs.map(pair=>{const left=byId.get(pair.leftId);const right=byId.get(pair.rightId);return \`<div class="ground-row"><div class="row-head"><strong>Possible duplicate options</strong><span class="tag warn">CHECK</span></div><p><strong>\${escapeHtml(left.name)}</strong> and <strong>\${escapeHtml(right.name)}</strong></p><p class="soft-copy">\${escapeHtml(pair.reason||'These may represent the same underlying decision mechanism.')}</p><div class="actions"><button class="secondary" data-action="duplicate-distinct" data-left="\${escapeAttr(left.id)}" data-right="\${escapeAttr(right.id)}">Keep both as distinct</button><button class="secondary" data-action="duplicate-remove" data-id="\${escapeAttr(right.id)}">Remove \${escapeHtml(right.name)}</button></div></div>\`}).join('')}

  function renderBetCard(bet,index){const line=state.ranking.pairwiseLines?.[index]||'';const selected=state.locks.selectedBetId===bet.id;return \`<article class="bet-card \${selected?'selected-bet':''}"><div class="rank">\${index+1}</div><div><div class="row-head"><div><span class="tag \${index===0?'good':''}">\${index===0?'LEADING':index===1?'CONTENDER':'LIVE'}</span><h3>\${escapeHtml(bet.name||'Untitled option')}</h3></div>\${bet.provisional?'<span class="tag warn">PROVISIONAL</span>':''}</div><p>\${escapeHtml(bet.description||'')}</p>\${line?\`<p class="comparison">\${escapeHtml(line)}</p>\`:''}<div class="evidence"><div><strong>Evidence against</strong><br>\${evidenceSummary(bet.evidenceAgainst)}</div><div><strong>Untested failures</strong><br>\${failureSummary(bet.failureModes)}</div></div><div class="actions"><button class="secondary" data-action="select-bet" data-id="\${escapeAttr(bet.id)}">\${selected?'Selected':'Carry this bet'}</button></div></div></article>\`}

  function renderBoardBetEditor(){const bet=state.bets.find(item=>item.id===boardAddingBetId);if(!bet)return '';return \`<article class="bet-edit" style="margin:12px 0"><div class="row-head"><strong>Add a live option</strong><button class="quiet" data-action="cancel-board-bet">Cancel</button></div><div class="grid"><div class="field"><label>Name</label><input data-bet="\${escapeAttr(bet.id)}" data-field="name" value="\${escapeAttr(bet.name)}" placeholder="Example: Phased relationship handoff"></div><div class="field"><label>What this bet changes</label><textarea data-bet="\${escapeAttr(bet.id)}" data-field="description" placeholder="Describe the option in concrete terms.">\${escapeHtml(bet.description)}</textarea></div></div><button data-action="save-board-bet">Add and evaluate</button></article>\`}
  function renderProvisionalBets(){const provisional=state.bets.filter(bet=>bet.liveStatus==='live'&&bet.provisional===true);if(!provisional.length)return '';return \`<div class="provisional-field" id="provisionalOptions"><strong>Suggested options to review</strong><div class="bet-list">\${provisional.map(renderBetEdit).join('')}</div></div>\`}

  function renderSetLine(){const coverage=state.ranking.coverage||{};const confirmed=['confirmed','confirmed_after_review'].includes(state.locks.setCompletenessConfirmation);const hard=module2SetNeedsExplicitReview(coverage.status,state.locks.setCompletenessConfirmation);const copy=hard?escapeHtml(coverage.gap||'The live field still has a gap.'):\`These \${admittedBets().length} options are the current full set.\`;return \`<section class="lock-block"><div class="row-head"><div><strong>Comparison set</strong><p class="soft-copy">\${copy}</p>\${!hard&&!confirmed?'<p class="soft-copy">This complete set will be accepted when you take a bet to Lock.</p>':''}</div><span class="tag \${hard?'bad':'good'}">\${confirmed?'CONFIRMED':hard?'REVIEW':'READY'}</span></div>\${hard?\`<button class="secondary" data-action="confirm-set">I reviewed the gap; carry this set</button>\`:''}</section>\`}
  function renderWeights(){ensureWeights();if(!state.weights.length)return '';return \`<details class="section"><summary>Reweight the comparison</summary><div style="padding-top:10px"><p class="soft-copy">Defaults are neutral-equal unless a basis trace is shown.</p>\${state.weights.map((weight,index)=>\`<div class="weight-row"><div><strong>\${escapeHtml(weight.criterion)}</strong><div class="soft-copy">\${escapeHtml(weight.basisType.replace('_',' '))}</div></div><input type="range" min="0" max="100" value="\${Math.round(Number(weight.weight||0)*100)}" data-weight="\${index}"><output>\${Math.round(Number(weight.weight||0)*100)}</output></div>\`).join('')}<div class="actions"><button class="secondary" data-action="rerank">Apply weights</button></div></div></details>\`}
  function renderBoardAction(){const blockers=boardBlockers();const ordered=orderedBets();const leader=ordered[0];if(blockers.length)return \`<button disabled>Resolve \${blockers.length} item\${blockers.length===1?'':'s'} before locking</button>\`;if(state.ranking.nearTie&&!state.locks.selectedBetId){const tied=ordered.slice(0,2);return \`<div class="hard-stop"><strong>The leading bets are effectively tied.</strong><p>Choose the one you are prepared to carry.</p><div class="actions">\${tied.map(bet=>\`<button class="secondary" data-action="select-bet" data-id="\${escapeAttr(bet.id)}">Carry \${escapeHtml(bet.name)}</button>\`).join('')}</div></div>\`}const selected=selectedBet()||leader;return \`<button data-action="to-lock" data-id="\${escapeAttr(selected?.id||'')}" \${selected?'':'disabled'}>Take \${escapeHtml(selected?.name||'selected bet')} to Lock</button>\`}

  function renderLock(){const bet=selectedBet();if(!bet)return \`<div class="empty">Choose a bet on the Board before locking the recommendation.</div><div class="actions"><button class="secondary" data-step="board">Back to Board</button></div>\`;return \`<section class="inheritance selected-bet"><div class="soft-copy">TAKING FORWARD</div><strong>\${escapeHtml(bet.name)}</strong><p>\${escapeHtml(bet.description)}</p></section><div class="grid"><section class="lock-block"><h2>Who absorbs the loss if this fails?</h2><p class="soft-copy">People mentioned so far are prompts, not a recommendation. The answer may be someone else.</p><div class="field"><label>Person or role</label><input data-path="locks.lossBearer" value="\${escapeAttr(state.locks.lossBearer)}" placeholder="Name the role or group"></div><div class="roster">\${ROSTER.map(name=>\`<button class="secondary" data-action="roster" data-value="\${escapeAttr(name)}">\${escapeHtml(name)}</button>\`).join('')}</div><div class="field"><label>Where accountability sits</label><textarea data-path="locks.accountabilityLocation" placeholder="Where would the consequence land, and who would have to respond?">\${escapeHtml(state.locks.accountabilityLocation)}</textarea></div></section><section class="lock-block"><h2>How reversible is this?</h2><div class="segmented">\${radio('locks.reversibility','reversible','Reversible',state.locks.reversibility)}\${radio('locks.reversibility','costly_to_reverse','Costly to reverse',state.locks.reversibility)}\${radio('locks.reversibility','one_way','One-way door',state.locks.reversibility)}</div><div class="field" style="margin-top:14px"><label>What makes it so?</label><textarea data-path="locks.reversibilityNote" placeholder="Name the commitment, cost, or recovery path.">\${escapeHtml(state.locks.reversibilityNote)}</textarea></div></section></div><section class="section lock-block"><div class="row-head"><div><h2>What the package will treat as fixed</h2><p class="soft-copy">Change anything that should remain open.</p></div><button class="secondary" data-action="add-held">Add</button></div>\${state.locks.heldConstant.length?state.locks.heldConstant.map((text,index)=>\`<div class="held-row"><input data-held="\${index}" value="\${escapeAttr(text)}"><button class="danger" data-action="remove-held" data-index="\${index}" aria-label="Remove held item">x</button></div>\`).join(''):'<div class="empty">Nothing is being held fixed yet.</div>'}</section>\${renderPackage()}<div class="sticky-action"><div class="actions"><button data-action="save-lock" \${lockReady()?'':'disabled'}>Save judgments</button><button class="secondary" data-step="board">Back to Board</button></div>\${lockReady()?'<p class="soft-copy">The recommendation is ready to package.</p>':'<p class="soft-copy">Name the loss bearer, accountability location, and reversibility before packaging.</p>'}</div>\`}

  function renderPackage(){const preview=state.package?.currentPreview;const versions=bundle?.versions||[];return \`<section class="section lock-block"><div class="row-head"><div><h2>Bethany House Recommendation Brief</h2><p class="soft-copy">\${preview?'Current recommendation ready for review.':'Generate the client brief from the locked decision.'}</p></div><div class="actions"><button data-action="generate-package" \${lockReady()?'':'disabled'}>Generate PDF</button><button class="secondary" data-action="save-version" \${lockReady()?'':'disabled'}>Save Version</button><button class="secondary" data-action="download-package" \${preview||pdfPreviewBlob?'':'disabled'}>Download PDF</button></div></div>\${preview?\`<div class="inheritance selected-bet"><strong>\${escapeHtml(preview.recommendation?.name||'Current recommendation')}</strong><p>\${escapeHtml(preview.currentPositionStatement||preview.recommendation?.summary||'')}</p></div>\`:''}\${pdfPreviewUrl?\`<iframe class="pdf-preview" src="\${escapeAttr(pdfPreviewUrl)}" title="Bethany House Recommendation Brief PDF"></iframe>\`:''}\${versions.length?\`<div class="version-list" style="margin-top:12px">\${versions.map(version=>\`<div class="version-row"><div><strong>Version \${version.version_number}</strong><div class="soft-copy">\${escapeHtml(formatDate(version.created_at))}</div></div><a href="\${escapeAttr(version.pdf_url)}" target="_blank" rel="noopener">Download saved PDF</a></div>\`).join('')}</div>\`:''}</section>\`}

  function entryTitle(entry){return entry==='full'?'Carried forward from Inquiry':entry==='partial'?'Partial Inquiry record found':'Starting from the material you provide'}
  function radio(path,value,label,current){return \`<label class="radio-card"><input type="radio" name="\${path}" data-path="\${path}" value="\${value}" \${current===value?'checked':''}>\${label}</label>\`}
  function admittedBets(){return state.bets.filter(bet=>bet.liveStatus==='live'&&bet.provisional!==true)}
  function orderedBets(){const byId=new Map(state.bets.map(bet=>[bet.id,bet]));const ordered=(state.ranking.orderedBetIds||[]).map(id=>byId.get(id)).filter(Boolean);const remaining=admittedBets().filter(bet=>!ordered.some(item=>item.id===bet.id));return [...ordered,...remaining]}
  function selectedBet(){return state.bets.find(bet=>bet.id===state.locks.selectedBetId)}
  function evidenceSummary(items){return items?.length?items.slice(0,2).map(item=>escapeHtml(item.text||item.severity||'Named objection')).join('<br>'):'None recorded'}
  function failureSummary(items){return items?.length?items.slice(0,2).map(item=>escapeHtml(item.text||item.severity||'Untested dependency')).join('<br>'):'None recorded'}
  function money(micros){return '$'+(Number(micros||0)/1000000).toFixed(2)}
  function boardBlockers(){const blockers=[];if(state.ground.voiceDisagreement?.status==='possible')blockers.push({message:'Confirm whether the attributed voices disagree before locking.'});if(module2FrameNeedsExplicitReview(state.ground.frameComparison?.status,state.locks.frameConfirmation))blockers.push({message:'Confirm or revise the decision frame in What I understood.'});const setNeedsReview=module2SetNeedsExplicitReview(state.ranking.coverage?.status,state.locks.setCompletenessConfirmation);if(setNeedsReview)blockers.push({message:state.ranking.coverage?.gap||'Review and confirm the current comparison set.',action:'set'});if(!setNeedsReview&&(state.ranking.evaluationIncomplete||!state.ranking.orderedBetIds?.length))blockers.push({message:state.ranking.incompleteReason||'Evaluate the live bets against one common criterion field.',action:'evaluate'});if(!state.ranking.evaluationIncomplete&&state.ranking.weakField)blockers.push({message:'The current leader dominates the other admitted options. Admit a genuinely different suggested mechanism, or ask for another.',action:'options'});return blockers}
  function lockReady(){return Boolean(selectedBet()&&meaningful(state.locks.lossBearer)&&meaningful(state.locks.accountabilityLocation)&&['reversible','costly_to_reverse','one_way'].includes(state.locks.reversibility)&&meaningful(state.locks.reversibilityNote))}
  function meaningful(value){return Boolean(String(value||'').trim())}
  function ensureWeights(){if(state?.weights?.length)return;const criteria=state?.bets?.find(bet=>bet.criteria?.length)?.criteria?.map(item=>item.criterion)||[];if(criteria.length){state.weights=criteria.map(criterion=>({criterion,weight:1/criteria.length,min:0,max:1,basisType:'neutral',basisTraceId:''}))}}

  async function save(step=currentStep,status='draft'){
    const data=await api('/api/studio/modules/module-2/workspace',{method:'PUT',body:JSON.stringify({state,currentStep:step,status})});state=data.state;bundle.versions=data.versions||bundle.versions;currentStep=step;return data;
  }
  async function saveJudgments(payload){const data=await api('/api/studio/modules/module-2/judgments',{method:'POST',body:JSON.stringify(payload)});state=data.state;currentStep=data.currentStep||currentStep;return data}
  async function saveLockJudgments(){await saveJudgments({lossBearer:state.locks.lossBearer,accountabilityLocation:state.locks.accountabilityLocation,reversibility:state.locks.reversibility,reversibilityNote:state.locks.reversibilityNote,heldConstant:state.locks.heldConstant});currentStep='lock';statusText='Judgments saved. Ready to package.'}
  async function runModule(module){const response=await api('/api/studio/llm',{method:'POST',body:JSON.stringify({module,payload:{}})});if(response.state)state=response.state;if(currentStep==='ground')includeNewGroundBets();if(response.usage)bundle.usage=response.usage;ensureWeights();return response}
  async function updateGroundOptions(){await save('ground');const result=await api('/api/studio/modules/module-2/ground',{method:'POST',body:JSON.stringify({problemSeed:state.ground.problemSeed,rawReply:state.ground.rawReply,solutionPaste:state.ground.solutionPaste,pickedIds:state.ground.pickedIds,excludedOptionIds:state.ground.excludedOptionIds,selectionInitialized:true})});state=result.state;statusText='Options updated.';return result}
  async function groundGo(){await updateGroundOptions();if(!state.bets.length)throw new Error('Select an option, add one, or ask the assistant for suggestions.');await runModule('m2_reconcile');if(admittedBets().length>=2)await runModule('m2_evaluate_bets');else await runModule('m2_suggest_options');currentStep='board';await save('board');statusText=admittedBets().length>=2?'Board ready.':'Review and admit a suggested alternative.'}
  async function suggest(){if(currentStep==='ground')await updateGroundOptions();else await save(currentStep);await runModule('m2_suggest_options');statusText='Options added as provisional. Admit the ones worth comparing.'}
  async function evaluate(){await save('board');if(admittedBets().length<2){await runModule('m2_suggest_options');statusText='Review and admit a suggested alternative before evaluation.';return}await runModule('m2_evaluate_bets');statusText='Comparison updated.'}
  async function reconcileBoard(message){await save('board');await runModule('m2_reconcile');if(admittedBets().length>=2)await runModule('m2_evaluate_bets');else await runModule('m2_suggest_options');statusText=message}
  async function rerank(){const result=await api('/api/studio/modules/module-2/rank',{method:'POST',body:JSON.stringify({weights:state.weights})});state=result.state;currentStep='board';statusText='Weights applied.'}
  async function generatePackage(saveVersion=false){await saveLockJudgments();await runModule('m2_package');const path=saveVersion?'/api/studio/modules/module-2/report/save-version':'/api/studio/modules/module-2/report/preview';const result=await api(path,{method:'POST',body:'{}'});if(result.state)state=result.state;if(result.versions)bundle.versions=result.versions;setPdfPreview(result.pdfBase64,result.filename);statusText=saveVersion?\`Version \${result.version?.version_number||''} saved.\`:'Recommendation PDF ready.'}
  async function ensurePackagePdf(){if(pdfPreviewBlob)return;const result=await api('/api/studio/modules/module-2/report/preview',{method:'POST',body:'{}'});if(result.versions)bundle.versions=result.versions;setPdfPreview(result.pdfBase64,result.filename)}

  document.addEventListener('click',async event=>{const button=event.target.closest('button');if(!button)return;const action=button.dataset.action;try{
    if(button.dataset.step){currentStep=button.dataset.step;render();return}
    if(action==='login'){await auth('/api/studio/auth/login',{email:value('loginEmail'),password:value('loginPassword')});return}
    if(action==='register'){await auth('/api/studio/auth/register',{name:value('regName'),email:value('regEmail'),password:value('regPassword'),classCode:value('regClassCode')});return}
    if(action==='logout'){await api('/api/studio/auth/logout',{method:'POST',body:'{}'});location.reload();return}
    if(action==='save'){await withBusy(async()=>{if(currentStep==='lock'&&lockReady())await saveLockJudgments();else await save();statusText='Saved.'});return}
    if(action==='add-bet'){const bet=newBet();state.ground.pickOptions.push(bet);state.ground.pickedIds.push(bet.id);state.bets.push(bet);render();return}
    if(action==='add-bet-board'){const bet=newBet();state.bets.push(bet);boardAddingBetId=bet.id;render();return}
    if(action==='cancel-board-bet'){state.bets=state.bets.filter(bet=>bet.id!==boardAddingBetId);boardAddingBetId='';render();return}
    if(action==='save-board-bet'){const bet=state.bets.find(item=>item.id===boardAddingBetId);if(!bet||!meaningful(bet.name)||!meaningful(bet.description))throw new Error('Name the option and what it changes before evaluating it.');boardAddingBetId='';state.locks.setCompletenessConfirmation='';await withBusy(evaluate);return}
    if(action==='remove-bet'||action==='remove-pick-option'){excludeOption(button.dataset.id);render();return}
    if(action==='admit-bet'){await withBusy(async()=>{const data=await api('/api/studio/modules/module-2/bets/'+encodeURIComponent(button.dataset.id)+'/admit',{method:'POST',body:'{}'});state=data.state;currentStep='board';statusText='Added to the live comparison. Evaluate the updated field.'});return}
    if(action==='update-ground-options'){await withBusy(updateGroundOptions);return}
    if(action==='ground-go'){await withBusy(groundGo);return}
    if(action==='suggest'){statusText='Developing distinct options...';await withBusy(suggest);return}
    if(action==='evaluate'){await withBusy(evaluate);return}
    if(action==='show-provisional'){document.getElementById('provisionalOptions')?.scrollIntoView({behavior:'smooth',block:'start'});return}
    if(action==='rerank'){await withBusy(rerank);return}
    if(action==='confirm-frame'){await withBusy(()=>saveJudgments({frameConfirmation:'confirmed'}));return}
    if(action==='revise-frame'){frameEditing=true;render();return}
    if(action==='cancel-frame-revision'){frameEditing=false;render();return}
    if(action==='save-frame-revision'){if(!meaningful(state.ground.frameComparison.groundedFrame))throw new Error('Write the revised decision frame before using it.');frameEditing=false;await withBusy(async()=>{await saveJudgments({revisedFrame:state.ground.frameComparison.groundedFrame});await reconcileBoard('Revised frame, reply, and comparison updated.')});return}
    if(action==='edit-reply'){replyCorrectionText='';replyEditing=true;render();return}
    if(action==='cancel-reply-edit'){replyEditing=false;render();return}
    if(action==='reconcile-reply'){if(!meaningful(replyCorrectionText))throw new Error('Paste the relevant Bethany House lines before reconciling them.');state.ground.rawReply=replyCorrectionText;replyEditing=false;replyCorrectionText='';await withBusy(()=>reconcileBoard('Reply and comparison updated.'));return}
    if(action==='voice-yes'||action==='voice-no'){await withBusy(async()=>{await saveJudgments({voiceDisposition:action==='voice-yes'?'confirmed':'dismissed'});await evaluate();statusText='Voice judgment recorded and comparison refreshed.'});return}
    if(action==='duplicate-distinct'){await withBusy(async()=>{await saveJudgments({duplicateDecision:{leftId:button.dataset.left,rightId:button.dataset.right,action:'keep_distinct'}});await rerank();statusText='Both options remain in the comparison.'});return}
    if(action==='duplicate-remove'){state.bets=state.bets.filter(bet=>bet.id!==button.dataset.id);state.ground.possibleDuplicates=(state.ground.possibleDuplicates||[]).filter(pair=>pair.leftId!==button.dataset.id&&pair.rightId!==button.dataset.id);await withBusy(evaluate);return}
    if(action==='confirm-set'){await withBusy(async()=>{await saveJudgments({setCompletenessConfirmation:'confirmed_after_review'});await rerank()});return}
    if(action==='select-bet'){await withBusy(()=>saveJudgments({selectedBetId:button.dataset.id,convictionNote:state.locks.convictionNote}));return}
    if(action==='to-lock'){const selectedBetId=button.dataset.id||state.locks.selectedBetId;const judgments={...module2LockTransitionJudgments({frameStatus:state.ground.frameComparison?.status,frameConfirmation:state.locks.frameConfirmation,coverageStatus:state.ranking.coverage?.status,setConfirmation:state.locks.setCompletenessConfirmation,selectedBetId}),convictionNote:state.locks.convictionNote};await saveJudgments(judgments);defaultHeld();currentStep='lock';render();return}
    if(action==='roster'){state.locks.lossBearer=button.dataset.value;render();return}
    if(action==='add-held'){state.locks.heldConstant.push('');render();return}
    if(action==='remove-held'){state.locks.heldConstant.splice(Number(button.dataset.index),1);render();return}
    if(action==='save-lock'){await withBusy(saveLockJudgments);return}
    if(action==='generate-package'){await withBusy(()=>generatePackage(false));return}
    if(action==='save-version'){await withBusy(()=>generatePackage(true));return}
    if(action==='download-package'){await withBusy(async()=>{await ensurePackagePdf();downloadBlob(pdfPreviewBlob,pdfPreviewFilename);statusText='PDF downloaded.'});return}
  }catch(error){statusText=error.message;render()}});

  document.addEventListener('input',event=>{const target=event.target;if(target.id==='replyCorrection')replyCorrectionText=target.value;if(target.dataset.path)setPath(state,target.dataset.path,target.value);if(target.dataset.bet){const options=[...(state.ground.pickOptions||[]),...(state.bets||[])];options.filter(item=>item.id===target.dataset.bet).forEach(item=>{item[target.dataset.field]=target.value})}if(target.dataset.weight!==undefined){const index=Number(target.dataset.weight);state.weights[index].weight=Number(target.value)/100;target.nextElementSibling.value=target.value}if(target.dataset.held!==undefined)state.locks.heldConstant[Number(target.dataset.held)]=target.value});
  document.addEventListener('change',event=>{const target=event.target;if(target.dataset.pick!==undefined){const ids=new Set(state.ground.pickedIds||[]);target.checked?ids.add(target.dataset.pick):ids.delete(target.dataset.pick);state.ground.pickedIds=[...ids];syncSelectedGroundBets();render()}if(target.dataset.path&&target.type==='radio'){setPath(state,target.dataset.path,target.value);render()}});

  async function auth(path,payload){await withBusy(async()=>{me=await api(path,{method:'POST',body:JSON.stringify(payload)});await loadWorkspace();statusText='';})}
  async function withBusy(fn){if(busy)return;busy=true;if(state)render();try{await fn()}catch(error){statusText=error.message}finally{busy=false;if(state)render();else renderAuth({message:statusText})}}
  function newBet(){return{id:'student-'+crypto.randomUUID(),name:'',description:'',origin:'student',provisional:false,liveStatus:'live',evidenceFor:[],evidenceAgainst:[],failureModes:[],criteria:[],frameBasisTraceIds:[],whyDistinct:'',evaluationStatus:'not_evaluated'}}
  function excludeOption(id){if(!id)return;const excluded=new Set(state.ground.excludedOptionIds||[]);excluded.add(id);state.ground.excludedOptionIds=[...excluded];state.bets=state.bets.filter(bet=>bet.id!==id);state.ground.pickOptions=(state.ground.pickOptions||[]).filter(bet=>bet.id!==id);state.ground.pickedIds=(state.ground.pickedIds||[]).filter(pickedId=>pickedId!==id)}
  function defaultHeld(){if(state.locks.heldConstant.length)return;const frame=state.ground.frameComparison?.groundedFrame||state.inheritance.frame;state.locks.heldConstant=['The recommendation is based on the consolidated reply supplied for this round.'];if(frame)state.locks.heldConstant.push('The current decision frame is: '+frame)}
  function setPdfPreview(base64,filename){if(pdfPreviewUrl)URL.revokeObjectURL(pdfPreviewUrl);const binary=atob(base64||'');const bytes=new Uint8Array(binary.length);for(let index=0;index<binary.length;index++)bytes[index]=binary.charCodeAt(index);pdfPreviewBlob=new Blob([bytes],{type:'application/pdf'});pdfPreviewFilename=filename||'bethany-house-recommendation-brief.pdf';pdfPreviewUrl=URL.createObjectURL(pdfPreviewBlob)}
  function downloadBlob(blob,filename){if(!blob)return;const link=document.createElement('a');link.href=URL.createObjectURL(blob);link.download=filename||'bethany-house-recommendation-brief.pdf';document.body.appendChild(link);link.click();link.remove();setTimeout(()=>URL.revokeObjectURL(link.href),1000)}
  function formatDate(value){const date=new Date(value);return Number.isNaN(date.getTime())?'Saved version':date.toLocaleString()}
  function value(id){return document.getElementById(id)?.value||''}
  function setPath(object,path,value){const parts=path.split('.');let cursor=object;while(parts.length>1){const part=parts.shift();cursor[part]=cursor[part]||{};cursor=cursor[part]}cursor[parts[0]]=value}
  function escapeHtml(value){return String(value??'').replace(/[&<>"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[char]))}
  function escapeAttr(value){return escapeHtml(value)}
</script></body></html>`;
}
